bundle A9_priority_order {
  frame {
    system Test;
    namespace Priority;
    scale service;
    task review;
    regime nominal;
  }

  evaluator ev_audit {
    kind audit;
    role audit;
    binding test://eval/audit_n_v1;
  }

  evaluator ev_model {
    kind model;
    role primary;
    binding test://eval/model_true_v1;
  }

  evaluator ev_fallback {
    kind model;
    role auxiliary;
    binding test://eval/fallback_false_v1;
